def correct_bracketing(brackets: str) -> bool:
    stack = []
    for b in brackets:
        if b == '(': stack.append(')')
        elif not stack or b != stack.pop(): return False
    return not stack

def tri(n):
    if n == 0:
        return [3]
    elif n == 1:
        return [3, 1]
    else:
        trib = [3, 1]
        for i in range(2, n + 1):
            if i % 2 == 0:
                trib.append(1 + i // 2)
            else:
                trib.append(trib[i - 1] + trib[i - 2] + trib[i + 1])
        return trib

def compare_one(a, b):
    if isinstance(a, str) and a.replace(',', '.').replace('.', ',') == b:
        return None
    elif isinstance(a, float) or isinstance(b, float):
        return max(float(a), float(b))
    else:
        return max(a, b)
